import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

const Header = () => {
  const [search, setSearch] = useState('');
  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  const handleSearch = (e) => {
    e.preventDefault();
    navigate(`/?search=${search}`);
  };

  const logout = () => {
    localStorage.removeItem('token');
    navigate('/login');
  };

  return (
    <nav className="bg-white shadow p-4 flex items-center justify-between">
      <Link to="/" className="text-so-orange text-2xl font-bold">
        Stack Clone
      </Link>
      <form onSubmit={handleSearch} className="flex-1 mx-4">
        <input
          type="text"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Search..."
          className="w-full p-2 border rounded"
        />
      </form>
      {token ? (
        <>
          <Link to="/ask" className="mx-2">Ask Question</Link>
          <Link to="/users/me" className="mx-2">Profile</Link>
          <button onClick={logout} className="mx-2">Logout</button>
        </>
      ) : (
        <Link to="/login">Login</Link>
      )}
    </nav>
  );
};

export default Header;
